/**
 * @fileoverview Slider class orchestrator.
 *
 * Imports helpers, state, view, and events sub-modules;
 * the class retains private fields but delegates work to those imports.
 *
 * @module module/Slider/index
 */
import { default as razyui } from '../../index.js';
import { DEFAULTS, CLS } from './constants.js';
import { snapValue } from './helpers.js';
import { createSliderState } from './state.js';
import { buildSliderDOM, wireEffects, setAriaAttrs, destroyDOM } from './view.js';
import { bindPointerEvents, bindKeyboard } from './events.js';
import { emitEvent } from '../shared/emitEvent.js';

/**
 * Slider — v2
 *
 * A range slider component with single or dual-thumb mode.
 * Reactive state via razyui.state(); property setters on getControl().
 *
 * Features:
 *   - Single value or range (dual thumb)
 *   - Configurable min / max / step
 *   - Keyboard navigation (← → ↑ ↓ Home End)
 *   - Optional value tooltip on drag
 *   - Optional tick marks
 *   - Disabled state
 *   - ARIA accessible (role=slider, aria-valuemin/max/now)
 *   - Callbacks: onChange
 *   - Programmatic API: getControl() with value get/set
 *
 * @class Slider
 */
const Slider = class {
    /** @type {Object|null} */
    #el = null;
    #destroyed = false;
    /** @type {Object|null} */
    #track = null;
    /** @type {Object|null} */
    #fill = null;
    /** @type {Object|null} */
    #thumbA = null;
    /** @type {Object|null} */
    #thumbB = null;
    /** @type {Object|null} */
    #tooltipA = null;
    /** @type {Object|null} */
    #tooltipB = null;
    /** @type {Object} */
    #config = {};
    /** @type {Object|null} */
    #stateRef = null;
    /** @type {Function|null} */
    #setState = null;
    /** @type {boolean} */
    #isRange = false;
    /** @type {Object|null} */
    #dragging = null;
    /** @type {Function|null} */
    #boundMove = null;
    /** @type {Function|null} */
    #boundUp = null;
    /** @type {AbortController} */
    #eventAC = new AbortController();
    #hiddenInput = null;

    /**
     * Creates an instance of Slider.
     *
     * @param {string|Element} selector - The selector or element to attach the slider to.
     * @param {Object} [config={}] - The configuration options.
     * @param {number} [config.min=0] - Minimum value.
     * @param {number} [config.max=100] - Maximum value.
     * @param {number} [config.step=1] - Step increment.
     * @param {number} [config.value] - Initial value for single mode.
     * @param {Array<number>} [config.range] - [low, high] for dual-thumb range mode.
     * @param {boolean} [config.showTooltip=true] - Show value tooltip on hover/drag.
     * @param {boolean} [config.showTicks=false] - Show tick marks for each step.
     * @param {boolean} [config.disabled=false] - Start disabled.
     * @param {Function} [config.formatValue] - Custom label formatter.
     * @param {Function} [config.onChange] - Callback when value changes.
     */
    constructor(selector, config = {}) {
        const el = razyui(selector);

        if (!el.length) {
            console.warn('Slider: element not found \u2192', selector);
            return;
        }

        this.#el = el;
        this.#config = { ...DEFAULTS, ...config };
        this.#isRange = Array.isArray(config.range);

        this.#init();
    }

    /**
     * Initialize the slider component.
     *
     * @private
     */
    #init() {
        const el  = this.#el;
        const cfg = this.#config;
        const isRange = this.#isRange;
        const min  = cfg.min  ?? DEFAULTS.min;
        const max  = cfg.max  ?? DEFAULTS.max;
        const step = cfg.step ?? DEFAULTS.step;

        // ── Build DOM ──
        const refs = buildSliderDOM(el, cfg, isRange);
        this.#track    = refs.track;
        this.#fill     = refs.fill;
        this.#thumbA   = refs.thumbA;
        this.#tooltipA = refs.tooltipA;
        this.#thumbB   = refs.thumbB;
        this.#tooltipB = refs.tooltipB;

        // ── Reactive state ──
        const { stateRef, setState, effect } = createSliderState(cfg, isRange);
        this.#stateRef = stateRef;
        this.#setState = setState;

        // ── Wire effects ──
        wireEffects(
            { track: refs.track, fill: refs.fill, wrapperA: refs.wrapperA, thumbA: refs.thumbA, tooltipA: refs.tooltipA,
              wrapperB: refs.wrapperB, thumbB: refs.thumbB, tooltipB: refs.tooltipB },
            stateRef, cfg, isRange, effect,
        );

        // ── ARIA ──
        setAriaAttrs(this.#thumbA, min, max);
        if (isRange) setAriaAttrs(this.#thumbB, min, max);

        // ── Pointer events ──
        const setThumbValue = (which, val) => this.#setThumbValue(which, val);
        const setDragging   = (v) => { this.#dragging = v; };
        const getDragging   = () => this.#dragging;

        const { boundMove, boundUp } = bindPointerEvents({
            el, track: refs.track, thumbA: refs.thumbA,
            config: cfg, isRange, stateRef,
            setThumbValue, setDragging, getDragging,
            signal: this.#eventAC.signal,
            tooltipA: this.#tooltipA, tooltipB: this.#tooltipB,
            portalTooltip: true,
        });
        this.#boundMove = boundMove;
        this.#boundUp = boundUp;

        // ── Keyboard ──
        const keyCtx = {
            config: cfg, stateRef, setThumbValue,
            thumbA: this.#thumbA, thumbB: this.#thumbB,
        };
        bindKeyboard(this.#thumbA, keyCtx, 'a', this.#eventAC.signal);
        if (isRange) bindKeyboard(this.#thumbB, keyCtx, 'b', this.#eventAC.signal);

        // Hidden input for native form submission
        if (cfg.name) {
            const hidden = document.createElement('input');
            hidden.type = 'hidden';
            hidden.name = cfg.name;
            hidden.value = isRange
                ? `${stateRef.a},${stateRef.b}`
                : String(stateRef.a);
            el[0].appendChild(hidden);
            this.#hiddenInput = hidden;
        }
    }

    // ── Internal helpers (still private, delegate to imported fns) ──

    /**
     * Set the value of a specific thumb.
     *
     * @private
     * @param {string} which - The thumb identifier ('a' or 'b').
     * @param {number} val - The new value.
     */
    #setThumbValue(which, val) {
        const isRange = this.#isRange;
        const st = this.#stateRef;

        if (isRange) {
            if (which === 'a') val = Math.min(val, st.b);
            else val = Math.max(val, st.a);
        }

        if (st[which] === val) return;

        this.#setState({ [which]: val });
        this.#fireChange();
    }

    /**
     * Fire the onChange callback.
     *
     * @private
     */
    #fireChange() {
        const val = this.#isRange
            ? [this.#stateRef.a, this.#stateRef.b]
            : this.#stateRef.a;
        if (this.#hiddenInput) {
            this.#hiddenInput.value = this.#isRange
                ? `${this.#stateRef.a},${this.#stateRef.b}`
                : String(this.#stateRef.a);
        }
        if (typeof this.#config.onChange === 'function') {
            this.#config.onChange.call(this, val);
        }
        if (this.#el?.[0]) emitEvent(this.#el[0], 'change', { value: val });
    }

    /**
     * Snap a value to the nearest step.
     *
     * @private
     * @param {number} value - The value to snap.
     * @returns {number} The snapped value.
     */
    #snap(value) {
        const min  = this.#config.min  ?? DEFAULTS.min;
        const max  = this.#config.max  ?? DEFAULTS.max;
        const step = this.#config.step ?? DEFAULTS.step;
        return snapValue(value, min, max, step);
    }

    // ── Public API ──

    /**
     * Get the current value.
     *
     * @returns {number|Array<number>} The current value (number for single, [low, high] for range).
     */
    get value() {
        return this.#isRange
            ? [this.#stateRef.a, this.#stateRef.b]
            : this.#stateRef.a;
    }

    /**
     * Set value programmatically.
     *
     * @param {number|Array<number>} v - The new value.
     */
    set value(v) {
        if (this.#isRange && Array.isArray(v)) {
            let [a, b] = v;
            a = this.#snap(a);
            b = this.#snap(b);
            if (a > b) [a, b] = [b, a];
            this.#setState({ a, b });
            this.#fireChange();
        } else if (!this.#isRange && typeof v === 'number') {
            const snapped = this.#snap(v);
            if (snapped !== this.#stateRef.a) {
                this.#setState({ a: snapped });
                this.#fireChange();
            }
        }
    }

    /**
     * Enable or disable the slider.
     *
     * @param {boolean} v - True to disable, false to enable.
     */
    set disabled(v) {
        this.#config.disabled = !!v;
        this.#setState({ disabled: !!v });
        this.#el.toggleClass('is-disabled', !!v);
        this.#el[0].setAttribute('aria-disabled', String(!!v));
    }

    setInvalid(invalid) {
        this.#el.toggleClass(CLS.INVALID, !!invalid);
        this.#el[0][invalid ? 'setAttribute' : 'removeAttribute']('aria-invalid', 'true');
    }

    focus() { this.#thumbA[0]?.focus(); }
    blur()  { this.#thumbA[0]?.blur(); }

    clear() {
        const min = this.#config.min;
        this.value = this.#isRange ? [min, min] : min;
    }

    /**
     * Check if the slider is disabled.
     *
     * @returns {boolean} True if disabled, false otherwise.
     */
    get disabled() {
        return !!this.#stateRef.disabled;
    }

    /**
     * Get a reactive control object.
     *
     * @returns {Object} The control object.
     */
    getControl() {
        const self = this;
        return {
            get value() { return self.value; },
            set value(v) { self.value = v; },
            get disabled() { return self.disabled; },
            set disabled(v) { self.disabled = v; },
            get min() { return self.#config.min; },
            set min(v) { self.#config.min = Number(v); self.value = self.value; },
            get max() { return self.#config.max; },
            set max(v) { self.#config.max = Number(v); self.value = self.value; },
            get step() { return self.#config.step; },
            set step(v) { self.#config.step = Number(v); self.value = self.value; },
            destroy:           () => self.destroy(),
            setInvalid:        (v) => self.setInvalid(v),
            checkValidity:     () => self.#hiddenInput ? self.#hiddenInput.checkValidity() : true,
            reportValidity:    () => self.#hiddenInput ? self.#hiddenInput.reportValidity() : true,
            setCustomValidity: (m) => { if (self.#hiddenInput) self.#hiddenInput.setCustomValidity(m || ''); self.setInvalid(!!m); },
            get label() { return self.#el[0].getAttribute('aria-label'); },
            set label(v) { v ? self.#el[0].setAttribute('aria-label', v) : self.#el[0].removeAttribute('aria-label'); },
            get labelledby() { return self.#el[0].getAttribute('aria-labelledby'); },
            set labelledby(v) { v ? self.#el[0].setAttribute('aria-labelledby', v) : self.#el[0].removeAttribute('aria-labelledby'); },
            get describedby() { return self.#el[0].getAttribute('aria-describedby'); },
            set describedby(v) { v ? self.#el[0].setAttribute('aria-describedby', v) : self.#el[0].removeAttribute('aria-describedby'); },
            focus: () => self.focus(),
            blur:  () => self.blur(),
            clear: () => self.clear(),
            get name() { return self.#config.name ?? ''; },
            set name(v) { self.#config.name = v; if (self.#hiddenInput) self.#hiddenInput.name = v; },
            get required() { return self.#config.required ?? false; },
            set required(v) { self.#config.required = !!v; if (self.#hiddenInput) self.#hiddenInput.required = !!v; self.#el[0].setAttribute('aria-required', String(!!v)); },
            get element() { return self.#el[0]; },
            get destroyed() { return self.#destroyed; },
        };
    }

    /**
     * Cleanup and restore original element.
     */
    destroy() {
        if (this.#destroyed) return;
        this.#destroyed = true;
        this.#eventAC?.abort();
        // Remove only this instance's document-level drag listeners (not all pointermove/pointerup)
        if (this.#boundMove) razyui(document).off('pointermove', this.#boundMove);
        if (this.#boundUp)   razyui(document).off('pointerup', this.#boundUp);
        this.#boundMove = null;
        this.#boundUp = null;
        if (this.#hiddenInput) { this.#hiddenInput.remove(); this.#hiddenInput = null; }
        destroyDOM(this.#el, { tooltipA: this.#tooltipA, tooltipB: this.#tooltipB });
    }
};

export default Slider;
