/**
 * @fileoverview Slider events — pointer and keyboard binding.
 * @module module/Slider/events
 */
import razyui from '../../index.js';
import { CLS, DEFAULTS } from './constants.js';
import { valueFromPointer, snapValue } from './helpers.js';

/**
 * Handle keyboard interaction on a thumb.
 *
 * @param {KeyboardEvent} e
 * @param {string}        which       — 'a' or 'b'
 * @param {object}        context
 * @param {object}        context.config
 * @param {object}        context.stateRef
 * @param {function}      context.setThumbValue
 * @param {HTMLElement}    context.thumbA
 * @param {HTMLElement}    context.thumbB
 */
function onKey(e, which, context) {
    const { config, stateRef, setThumbValue, thumbA, thumbB } = context;
    if (config.disabled) return;

    const step = config.step ?? DEFAULTS.step;
    const min  = config.min  ?? DEFAULTS.min;
    const max  = config.max  ?? DEFAULTS.max;
    const current = stateRef[which];
    let next = current;

    switch (e.key) {
        case 'ArrowRight':
        case 'ArrowUp':
            e.preventDefault();
            next = snapValue(current + step, min, max, step);
            break;
        case 'ArrowLeft':
        case 'ArrowDown':
            e.preventDefault();
            next = snapValue(current - step, min, max, step);
            break;
        case 'Home':
            e.preventDefault();
            next = min;
            break;
        case 'End':
            e.preventDefault();
            next = max;
            break;
        default:
            return;
    }

    setThumbValue(which, next);

    // Focus the active thumb
    const thumb = which === 'a' ? thumbA : thumbB;
    thumb[0].focus();
}

/**
 * Bind pointerdown on the track and pointermove / pointerup on document.
 *
 * @param {object}   context
 * @param {HTMLElement} context.el
 * @param {HTMLElement} context.track
 * @param {HTMLElement} context.thumbA
 * @param {object}   context.config
 * @param {boolean}  context.isRange
 * @param {object}   context.stateRef
 * @param {function} context.setThumbValue
 * @param {function} context.setDragging   — (value) => void
 * @param {function} context.getDragging   — () => 'a'|'b'|null
 * @param {AbortSignal} [context.signal]   — signal for cleanup via AbortController
 * @returns {{ boundMove: function, boundUp: function }}
 */
export function bindPointerEvents(context) {
    const {
        el, track, thumbA, config, isRange,
        stateRef, setThumbValue, setDragging, getDragging, signal,
        tooltipA, tooltipB, portalTooltip,
    } = context;

    const min  = config.min  ?? DEFAULTS.min;
    const max  = config.max  ?? DEFAULTS.max;
    const step = config.step ?? DEFAULTS.step;

    const snapFn = (v) => snapValue(v, min, max, step);
    let cachedRect = null;

    /** Show/hide portaled tooltips */
    function setPortalVisible(visible) {
        if (!portalTooltip) return;
        const s = visible ? '1' : '0';
        if (tooltipA?.[0]) { tooltipA.css('opacity', s); }
        if (tooltipB?.[0]) { tooltipB.css('opacity', s); }
    }

    function onPointerMove(e) {
        if (!getDragging() || !cachedRect) return;
        const ratio = Math.max(0, Math.min(1, (e.clientX - cachedRect.left) / cachedRect.width));
        const val = snapFn(min + ratio * (max - min));
        setThumbValue(getDragging(), val);
    }

    function onPointerUp() {
        setDragging(null);
        cachedRect = null;
        el.removeClass(CLS.DRAGGING);
        setPortalVisible(false);
        razyui(document).off('pointermove', onPointerMove);
        razyui(document).off('pointerup', onPointerUp);
    }

    razyui(track).on('pointerdown', (e) => {
        if (config.disabled) return;
        e.preventDefault();

        const rawTrack = track?.[0] ?? track;
        cachedRect = rawTrack.getBoundingClientRect();

        const thumbEl = razyui(e.target).closest('.' + CLS.THUMB);
        if (thumbEl.length) {
            setDragging(thumbEl[0] === thumbA[0] ? 'a' : 'b');
        } else {
            // Click on track — move closest thumb
            const ratio = Math.max(0, Math.min(1, (e.clientX - cachedRect.left) / cachedRect.width));
            const val = snapFn(min + ratio * (max - min));
            if (isRange) {
                const distA = Math.abs(val - stateRef.a);
                const distB = Math.abs(val - stateRef.b);
                setDragging(distA <= distB ? 'a' : 'b');
            } else {
                setDragging('a');
            }
            setThumbValue(getDragging(), val);
        }

        el.addClass(CLS.DRAGGING);
        setPortalVisible(true);
        razyui(document).on('pointermove', onPointerMove);
        razyui(document).on('pointerup', onPointerUp);
    }, signal ? { signal } : undefined);

    return { boundMove: onPointerMove, boundUp: onPointerUp };
}

/**
 * Bind keyboard navigation on a thumb.
 *
 * @param {HTMLElement} thumb
 * @param {object}      context — same shape as onKey's context
 * @param {string}      which   — 'a' or 'b'
 * @param {AbortSignal} [signal] — signal for cleanup via AbortController
 */
export function bindKeyboard(thumb, context, which, signal) {
    razyui(thumb).on('keydown', (e) => onKey(e, which, context), signal ? { signal } : undefined);
}
