/**
 * @fileoverview Slider component definition for JIT pipeline.
 *
 * @module module/Slider.def
 */

import razyui from '../index.js';
import { PART } from './Slider/constants.js';

/**
 * The definition object for the Slider component.
 * Contains metadata, tokens, states, templates, variants, and attribute mappings.
 *
 * @type {Object}
 */
export const SliderDef = {
    name: 'Slider',
    tag: 'rui-slider',

    tokens: {
        prefix: 'sl',
        tokens: {
            'padding-y':          { value: '0.75rem',                          description: 'Root vertical padding' },
            'padding-x':          { value: 'calc(var(--sl-thumb-size) / 2)',   description: 'Root horizontal padding (half thumb)' },
            'track-height':       { value: '6px',                description: 'Track height' },
            'track-radius':       { ref: 'radius.sm',           description: 'Track border radius' },
            'thumb-size':         { value: '18px',               description: 'Thumb diameter' },
            'thumb-border-width': { value: '2px',                description: 'Thumb border width' },
            'tick-width':         { value: '2px',                description: 'Tick mark width' },
            'tick-height':        { value: '12px',               description: 'Tick mark height' },
            'tooltip-padding-y':  { value: '0.15rem',            description: 'Tooltip vertical padding' },
            'tooltip-padding-x':  { value: '0.45rem',            description: 'Tooltip horizontal padding' },
            'tooltip-radius':     { ref: 'radius.sm',            description: 'Tooltip border radius' },
            'tooltip-font-size':  { value: '0.5rem',              description: 'Tooltip font size' },
            'accent':             { ref: 'color.accent',         description: 'Active track / thumb color' },
            'accent-subtle':      { ref: 'color.accent-subtle',  description: 'Focus ring color' },
            'bg':                 { ref: 'color.bg',             description: 'Thumb background' },
            'bg-inset':           { ref: 'color.bg-inset',       description: 'Track background' },
            'border':             { ref: 'color.border',         description: 'Border color' },
            'border-strong':      { ref: 'color.border-strong',  description: 'Tick mark color' },
            'font-stack':         { ref: 'font.family',          description: 'Font family' },
            'shadow':             { ref: 'shadow.sm',            description: 'Thumb shadow' },
            'text':               { ref: 'color.text',           description: 'Label text color' },
            'text-muted':         { ref: 'color.text-muted',     description: 'Muted text' },
            'tooltip-bg':         { value: '#1e293b',            description: 'Tooltip background' },
            'tooltip-text':       { value: '#fff',               description: 'Tooltip text color' },
        },
    },

    states: {
        initial: 'idle',
        states: {
            idle:     { on: { DRAG_START: 'dragging', DISABLE: 'disabled' } },
            dragging: { on: { DRAG_END: 'idle' } },
            disabled: { on: { ENABLE: 'idle' } },
        },
        effects: {
            dragging(ctx) {
                if (ctx.el) razyui(ctx.el).addClass('is-dragging');
            },
            'dragging:exit'(ctx) {
                if (ctx.el) razyui(ctx.el).removeClass('is-dragging');
            },
            disabled(ctx) {
                if (ctx.el) razyui(ctx.el).addClass('is-disabled');
            },
            'disabled:exit'(ctx) {
                if (ctx.el) razyui(ctx.el).removeClass('is-disabled');
            },
        },
    },

    template: {
        slots: {
            root:    { element: 'div', classes: ['slider'] },
            track:   { element: 'div', classes: ['slider-track'] },
            fill:    { element: 'div', classes: ['slider-fill'] },
            thumb:   { element: 'div', classes: ['slider-thumb'] },
            tick:    { element: 'span', classes: ['slider-tick'] },
            tooltip: { element: 'div', classes: ['slider-tooltip'] },
            label:   { element: 'span', classes: ['slider-label'] },
        },
    },

    variants: {
        vertical: { description: 'Vertical orientation' },
        range:    { description: 'Dual-thumb range mode' },
    },

    observedAttrs: ['value', 'min', 'max', 'step', 'disabled'],
    attrMap: {
        value: 'value',
        min: 'min',
        max: 'max',
        step: 'step',
        disabled: 'disabled',
    },

    jitParts: {
        [PART.ROOT]: PART.ROOT,
        [PART.TRACK]: PART.TRACK,
        [PART.FILL]: PART.FILL,
        [PART.THUMB]: PART.THUMB,
        [PART.TOOLTIP]: PART.TOOLTIP,
        [PART.TICKS]: PART.TICKS,
        [PART.TICK]: PART.TICK,
    },

    styles: {},  /* All styles expressed via JIT */
};

export default SliderDef;
